import{L as e,b as t,x as n}from"./vue-BDJHnCxa.js";import{t as r}from"./app-DcQgDZmH.js";var i=JSON.parse(`{"path":"/blog/73zyziql/","title":"WSL SSH 服务自启动与配置指南 | Blog","lang":"zh-CN","frontmatter":{"title":"WSL SSH 服务自启动与配置指南","createTime":"2025/11/20 15:59:49","permalink":"/blog/73zyziql/","description":"问题背景 在默认配置下，WSL (Windows Subsystem for Linux) 实例启动时不会自动拉起后台服务。导致每次打开 WSL 终端后，都必须手动运行 sudo service ssh restart 才能通过 SSH 连接。 解决方案：启用 Systemd 推荐方案 通过开启 WSL 2 的 systemd 支持，可以让 SSH 服...","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"WSL SSH 服务自启动与配置指南\\",\\"image\\":[\\"\\"],\\"dateModified\\":null,\\"author\\":[]}"],["meta",{"property":"og:url","content":"https://powersen.cn/blog/73zyziql/"}],["meta",{"property":"og:site_name","content":"Powersen"}],["meta",{"property":"og:title","content":"WSL SSH 服务自启动与配置指南"}],["meta",{"property":"og:description","content":"问题背景 在默认配置下，WSL (Windows Subsystem for Linux) 实例启动时不会自动拉起后台服务。导致每次打开 WSL 终端后，都必须手动运行 sudo service ssh restart 才能通过 SSH 连接。 解决方案：启用 Systemd 推荐方案 通过开启 WSL 2 的 systemd 支持，可以让 SSH 服..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}]]},"readingTime":{"minutes":1.9,"words":570},"git":{"createdTime":1779970460000},"autoDesc":true,"filePathRelative":"blog/5.其他/wsl_ssh_setup.md","headers":[],"categoryList":[{"id":"9319d1","sort":5,"name":"其他"}]}`),a={name:`wsl_ssh_setup.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<h2 id="问题背景" tabindex="-1"><a class="header-anchor" href="#问题背景"><span>问题背景</span></a></h2><p>在默认配置下，WSL (Windows Subsystem for Linux) 实例启动时不会自动拉起后台服务。导致每次打开 WSL 终端后，都必须手动运行 <code>sudo service ssh restart</code> 才能通过 SSH 连接。</p><h2 id="解决方案-启用-systemd" tabindex="-1"><a class="header-anchor" href="#解决方案-启用-systemd"><span>解决方案：启用 Systemd</span></a></h2><div class="hint-container tip"><p class="hint-container-title">推荐方案</p><p>通过开启 WSL 2 的 <code>systemd</code> 支持，可以让 SSH 服务像在标准 Linux 服务器上一样开机自启。</p></div><h3 id="第一步-修改-wsl-启动配置" tabindex="-1"><a class="header-anchor" href="#第一步-修改-wsl-启动配置"><span>第一步：修改 WSL 启动配置</span></a></h3><p>在 WSL 终端中执行以下命令：</p><ol><li>编辑配置文件：</li></ol><div class="language-bash line-numbers-mode" data-highlighter="shiki" data-ext="bash" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-bash"><span class="line"><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">sudo</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> nano</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> /etc/wsl.conf</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="2"><li>添加（或修改）以下内容：</li></ol><div class="language-ini line-numbers-mode" data-highlighter="shiki" data-ext="ini" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-ini"><span class="line"><span style="--shiki-light:#999999;--shiki-dark:#666666;">[</span><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">boot</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">]</span></span>
<span class="line"><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">systemd</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">=</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">true</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ol start="3"><li>保存并退出（<code>Ctrl+O</code> 保存 → <code>Enter</code> 确认 → <code>Ctrl+X</code> 退出）</li></ol><h3 id="第二步-重启-wsl-实例" tabindex="-1"><a class="header-anchor" href="#第二步-重启-wsl-实例"><span>第二步：重启 WSL 实例</span></a></h3><p>配置需要重启 WSL 才能生效。请<strong>关闭所有 WSL 窗口</strong>，然后在 Windows 的 <strong>PowerShell</strong> 中执行：</p><div class="language-powershell line-numbers-mode" data-highlighter="shiki" data-ext="powershell" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-powershell"><span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">wsl </span><span style="--shiki-light:#999999;--shiki-dark:#666666;">--</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">shutdown</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="第三步-启用-ssh-服务自启" tabindex="-1"><a class="header-anchor" href="#第三步-启用-ssh-服务自启"><span>第三步：启用 SSH 服务自启</span></a></h3><p>重新打开 WSL 终端，此时 Systemd 已经生效。执行以下命令将 SSH 加入自启列表：</p><div class="language-bash line-numbers-mode" data-highlighter="shiki" data-ext="bash" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-bash"><span class="line"><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">sudo</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> systemctl</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> enable</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> ssh</span></span>
<span class="line"><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">sudo</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> systemctl</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> start</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> ssh</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container info"><p class="hint-container-title">相关信息</p><p>如果看到 <code>Synchronizing state of ssh.service...</code> 的提示，说明设置成功。</p></div><h2 id="进阶配置-允许-root-用户登录" tabindex="-1"><a class="header-anchor" href="#进阶配置-允许-root-用户登录"><span>进阶配置：允许 Root 用户登录</span></a></h2><div class="hint-container warning"><p class="hint-container-title">注意</p><p>由于 WSL 默认常以 Root 身份操作，而 SSH 默认配置通常禁止 Root 用户使用密码登录，因此需要修改 SSH 配置文件，否则连接时会提示&quot;密码错误&quot;或&quot;Permission denied&quot;。</p></div><h3 id="修改-sshd-配置" tabindex="-1"><a class="header-anchor" href="#修改-sshd-配置"><span>修改 SSHD 配置</span></a></h3><ol><li>在 WSL 中编辑 SSH 配置文件：</li></ol><div class="language-bash line-numbers-mode" data-highlighter="shiki" data-ext="bash" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-bash"><span class="line"><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">sudo</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> nano</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> /etc/ssh/sshd_config</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="2"><li>找到并修改以下参数（如果被注释掉，请删除行首的 <code>#</code>）：</li></ol><ul><li><strong>允许 Root 登录：</strong></li></ul><div class="language-plaintext line-numbers-mode" data-highlighter="shiki" data-ext="plaintext" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-plaintext"><span class="line"><span>PermitRootLogin yes</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li><strong>允许密码验证</strong>（通常默认为 yes，确认一下）：</li></ul><div class="language-plaintext line-numbers-mode" data-highlighter="shiki" data-ext="plaintext" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-plaintext"><span class="line"><span>PasswordAuthentication yes</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="3"><li>重启 SSH 服务使配置生效：</li></ol><div class="language-bash line-numbers-mode" data-highlighter="shiki" data-ext="bash" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-bash"><span class="line"><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">sudo</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> systemctl</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> restart</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> ssh</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="验证与测试" tabindex="-1"><a class="header-anchor" href="#验证与测试"><span>验证与测试</span></a></h2><h3 id="检查服务状态" tabindex="-1"><a class="header-anchor" href="#检查服务状态"><span>检查服务状态</span></a></h3><p>在 WSL 中运行：</p><div class="language-bash line-numbers-mode" data-highlighter="shiki" data-ext="bash" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-bash"><span class="line"><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">systemctl</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> status</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> ssh</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>::: success 正常状态 显示绿色的 <code>active (running)</code> :::</p><h3 id="测试连接" tabindex="-1"><a class="header-anchor" href="#测试连接"><span>测试连接</span></a></h3><p>在 Windows PowerShell 或 CMD 中尝试连接：</p><div class="language-powershell line-numbers-mode" data-highlighter="shiki" data-ext="powershell" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-powershell"><span class="line"><span style="--shiki-light:#A0ADA0;--shiki-dark:#758575DD;"># 默认连接本地 WSL</span></span>
<span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">ssh root</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">@</span><span style="--shiki-light:#B07D48;--shiki-dark:#BD976A;">localhost</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container note"><p class="hint-container-title">注</p><p>如果 Windows 也占用了 22 端口，可能需要修改 WSL 的 SSH 端口为 2222 等其他端口</p></div><h2 id="扩展阅读" tabindex="-1"><a class="header-anchor" href="#扩展阅读"><span>扩展阅读</span></a></h2><p>如需配置端口转发，以便让局域网内的其他设备访问您的 WSL，可以查阅相关网络配置文档。</p>`,41)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};